-        "$ref": "#/$defs/search_result"
+        "$ref": "#/$defs/search_hit"
       }
     },
-    "total_matches": {
+    "total_hits": {
       "type": "integer",
       "minimum": 0,
-      "description": "Total number of matches (may exceed returned results if limited)"
+      "description": "Total number of hits (may exceed returned results if limited)"
     },
     "limit": {
       "type": "integer",
@@ -32,32 +32,20 @@
       "minimum": 0,
       "description": "If set, results were filtered to this pane_id"
     },
