@@ -2,78 +2,38 @@
   "$schema": "https://json-schema.org/draft/2020-12/schema",
   "$id": "https://wezterm-automata.dev/schemas/wa-robot-wait-for.json",
   "title": "WA Robot Wait-For Response",
