+  "description": "Schema for the data field when calling 'wa robot wait-for' or 'wa send --wait-for'. Waits for a pattern to match.",
   "type": "object",
-  "required": ["pane_id", "rule_id", "matched", "waited_ms"],
+  "required": ["pane_id", "pattern", "matched", "elapsed_ms", "polls"],
   "properties": {
     "pane_id": {
       "type": "integer",
       "minimum": 0,
       "description": "The pane being monitored"
     },
-    "rule_id": {
+    "pattern": {
       "type": "string",
-      "description": "The pattern rule being waited for"
+      "description": "The pattern string being waited for"
     },
     "matched": {
       "type": "boolean",
       "description": "Whether the pattern was matched before timeout"
     },
-    "timeout_ms": {
+    "elapsed_ms": {
       "type": "integer",
       "minimum": 0,
-      "description": "The timeout that was configured"
+      "description": "Actual time spent waiting (milliseconds)"
     },
-    "waited_ms": {
+    "polls": {
       "type": "integer",
       "minimum": 0,
-      "description": "Actual time spent waiting"
+      "description": "Number of polling attempts"
     },
-    "timed_out": {
+    "is_regex": {
       "type": "boolean",
-      "description": "True if the wait ended due to timeout"
-    },
-    "detection": {
-      "$ref": "#/$defs/detection",
-      "description": "Details of the detection (present when matched=true)"
