+      "description": "True if the pattern is a regex, false for substring match"
     }
   },
-  "additionalProperties": false,
-  "$defs": {
-    "detection": {
-      "type": "object",
-      "description": "Pattern detection details",
-      "required": ["rule_id", "event_type", "detected_at"],
