-        "rule_id": {
-          "type": "string",
-          "description": "The rule that matched"
-        },
-        "event_type": {
-          "type": "string",
-          "description": "Type of event detected"
-        },
-        "severity": {
-          "type": "string",
-          "enum": ["info", "warning", "critical"]
-        },
-        "confidence": {
-          "type": "number",
-          "minimum": 0,
-          "maximum": 1
-        },
-        "extracted": {
-          "type": "object",
-          "description": "Extracted values from the pattern",
-          "additionalProperties": true
-        },
-        "detected_at": {
-          "type": "integer",
-          "minimum": 0,
-          "description": "Unix timestamp (ms)"
-        }
-      },
-      "additionalProperties": false
-    }
-  }
+  "additionalProperties": false
 }
